{"code":"import json, ast
# Parse globals for var_call_ entries
results = []
for k in list(globals().keys()):
    if k.startswith('var_call_'):
        v = globals()[k]
        if isinstance(v, str):
            # find first '[' and last ']'
            a = v.find('[')
            b = v.rfind(']')
            if a!=-1 and b!=-1 and b>a:
                part = v[a:b+1]
                try:
                    data = ast.literal_eval(part)
                    if isinstance(data, list) and len(data)>0 and isinstance(data[0], dict) and 'symbol' in data[0]:
                        d = data[0]
                        # ensure cnt is int
                        try:
                            cnt = int(d.get('cnt', 0))
                        except:
                            cnt = 0
                        results.append({'symbol': d.get('symbol'), 'cnt': cnt})
                except Exception:
                    pass
# deduplicate by symbol, keep max cnt
agg = {}
for r in results:
    s = r['symbol']
    if s not in agg or r['cnt']>agg[s]:
        agg[s] = r['cnt']
# make list
rows = [{'symbol': s, 'cnt': agg[s]} for s in agg]
rows_sorted = sorted(rows, key=lambda x: x['cnt'], reverse=True)
top5 = rows_sorted[:5]
symbols_top5 = [r['symbol'] for r in top5]
print('__RESULT__:')
print(json.dumps({'top5': top5, 'symbols': symbols_top5}))"}

